function pacificAtlantic(heights) {
    const m = heights.length, n = heights[0].length;
    function bfs(starts) {
        const visited = new Set(starts.map(([r, c]) => r * n + c));
        const queue = [...starts];
        let i = 0;
        while (i < queue.length) {
            const [r, c] = queue[i++];
            for (const [dr, dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < m && nc >= 0 && nc < n &&
                    !visited.has(nr * n + nc) && heights[nr][nc] >= heights[r][c]) {
                    visited.add(nr * n + nc);
                    queue.push([nr, nc]);
                }
            }
        }
        return visited;
    }
    const pacStarts = [], atlStarts = [];
    for (let r = 0; r < m; r++) {
        pacStarts.push([r, 0]); atlStarts.push([r, n - 1]);
    }
    for (let c = 0; c < n; c++) {
        pacStarts.push([0, c]); atlStarts.push([m - 1, c]);
    }
    const pac = bfs(pacStarts), atl = bfs(atlStarts);
    const result = [];
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (pac.has(r * n + c) && atl.has(r * n + c)) result.push([r, c]);
        }
    }
    return result;
}
